use style::stylesheets::container_rule::{ContainerCondition, ContainerSizeQuery};
use style::stylist::ContainerConditionId;
use style::values::specified::box_::{ContainerName, ContainerType};
use style_traits::ToCss;

use super::parse;

// ── ContainerSizeQuery ────────────────────────────────────────────────────────

#[test]
fn test_container_size_query_none_is_evaluated() {
    let query = ContainerSizeQuery::none();
    assert!(
        matches!(query, ContainerSizeQuery::Evaluated(_)),
        "none() must produce the Evaluated variant"
    );
}

#[test]
fn test_container_size_query_get_on_evaluated() {
    let mut query = ContainerSizeQuery::none();
    let _ = query.get();
    // Calling get() on an already-evaluated query must leave it Evaluated.
    assert!(matches!(query, ContainerSizeQuery::Evaluated(_)));
}

// ── ContainerConditionId ──────────────────────────────────────────────────────

#[test]
fn test_container_condition_id_none_equality() {
    let a = ContainerConditionId::none();
    let b = ContainerConditionId::none();
    assert_eq!(a, b);
    // Two `none()` values must be equal, so neither is less than the other.
    assert!(!(a < b));
    assert!(!(a > b));
}

// ── ContainerName ─────────────────────────────────────────────────────────────

#[test]
fn test_container_name_none_is_none() {
    let name = ContainerName::none();
    assert!(name.is_none());
    assert_eq!(ToCss::to_css_string(&name), "none");
}

#[test]
fn test_container_name_parse_none_keyword() {
    // The CSS keyword "none" must parse to the none() value.
    let parsed = parse(ContainerName::parse, "none").unwrap();
    assert!(parsed.is_none());
    assert_eq!(ToCss::to_css_string(&parsed), "none");
}

#[test]
fn test_container_name_single_ident_roundtrip() {
    assert_roundtrip_with_context!(ContainerName::parse, "sidebar");
}

#[test]
fn test_container_name_multiple_idents_roundtrip() {
    assert_roundtrip_with_context!(ContainerName::parse, "sidebar card");
}

#[test]
fn test_container_name_parse_for_query_rejects_reserved_words() {
    // These keywords are reserved and must be rejected by parse_for_query.
    assert!(parse(ContainerName::parse_for_query, "none").is_err());
    assert!(parse(ContainerName::parse_for_query, "not").is_err());
    assert!(parse(ContainerName::parse_for_query, "and").is_err());
    assert!(parse(ContainerName::parse_for_query, "or").is_err());
}

#[test]
fn test_container_name_parse_for_query_accepts_valid_ident() {
    let parsed = parse(ContainerName::parse_for_query, "sidebar").unwrap();
    assert!(!parsed.is_none());
    assert_eq!(ToCss::to_css_string(&parsed), "sidebar");
}

// ── ContainerType ─────────────────────────────────────────────────────────────

#[test]
fn test_container_type_flags() {
    assert!(ContainerType::NORMAL.is_normal());
    assert!(!ContainerType::SIZE.is_normal());
    assert!(!ContainerType::INLINE_SIZE.is_normal());

    assert!(ContainerType::SIZE.is_size_container_type());
    assert!(ContainerType::INLINE_SIZE.is_size_container_type());
    assert!(!ContainerType::NORMAL.is_size_container_type());
}

#[test]
fn test_container_type_roundtrip() {
    assert_roundtrip_with_context!(ContainerType::parse, "normal");
    assert_roundtrip_with_context!(ContainerType::parse, "size");
    assert_roundtrip_with_context!(ContainerType::parse, "inline-size");
}

#[test]
fn test_container_type_mixed_size_flags_rejected() {
    // Combining size and inline-size is invalid per the spec.
    assert!(parse(ContainerType::parse, "size inline-size").is_err());
}

// ── ContainerCondition ────────────────────────────────────────────────────────

#[test]
fn test_container_condition_simple_width_range() {
    assert_roundtrip_with_context!(ContainerCondition::parse, "(width > 300px)");
}

#[test]
fn test_container_condition_legacy_min_range() {
    assert_roundtrip_with_context!(ContainerCondition::parse, "(min-width: 300px)");
}

#[test]
fn test_container_condition_named_container() {
    assert_roundtrip_with_context!(ContainerCondition::parse, "sidebar (width > 700px)");
}

#[test]
fn test_container_condition_negation() {
    assert_roundtrip_with_context!(ContainerCondition::parse, "not (width > 300px)");
}

#[test]
fn test_container_condition_and() {
    assert_roundtrip_with_context!(
        ContainerCondition::parse,
        "(width > 300px) and (height > 200px)"
    );
}

#[test]
fn test_container_condition_or() {
    assert_roundtrip_with_context!(
        ContainerCondition::parse,
        "(width > 300px) or (height > 200px)"
    );
}

#[test]
fn test_container_condition_named_with_negation() {
    assert_roundtrip_with_context!(ContainerCondition::parse, "card not (width > 500px)");
}

#[test]
fn test_container_condition_boolean_context() {
    // A bare feature name in parens is valid (boolean context).
    assert_roundtrip_with_context!(ContainerCondition::parse, "(width)");
}

#[test]
fn test_container_condition_missing_parens_rejected() {
    // Feature expressions must be wrapped in parentheses.
    assert!(parse(ContainerCondition::parse, "width > 300px").is_err());
}

